const data = $input.first().json;
const comments = data.comments;

if (!comments || comments.length === 0) {
  return [{ json: { error: "No comments found" } }];
}

// Sort by created_at descending and take the first (most recent)
const lastComment = [...comments].sort(
  (a, b) => new Date(b.created_at) - new Date(a.created_at)
)[0];

return [
  {
    json: {
      id: lastComment.id,
      author_id: lastComment.author_id,
      body: lastComment.plain_body,
      public: lastComment.public,
      created_at: lastComment.created_at,
      channel: lastComment.via?.channel ?? null
    },
  },
];

