const data = $input.first().json;
const comments = data.comments;

if (!comments || comments.length === 0) {
  return [{ json: { error: "No comments found" } }];
}

// A comment is from the customer if via.source.to has no address
const isFromCustomer = (comment) => {
  const to = comment?.via?.source?.to;
  return !to?.address;
};

// Filter to customer comments only, then sort by created_at descending
const customerComments = comments
  .filter(isFromCustomer)
  .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

if (customerComments.length === 0) {
  return [{ json: { error: "No customer comments found" } }];
}

const lastCustomerComment = customerComments[0];

return [
  {
    json: {
      id: lastCustomerComment.id,
      author_id: lastCustomerComment.author_id,
      body: lastCustomerComment.plain_body,
      public: lastCustomerComment.public,
      created_at: lastCustomerComment.created_at,
      channel: lastCustomerComment.via?.channel ?? null,
    },
  },
];

